={
  "model": "llama3.2:3b",
  "prompt": {{('Voce e Jarvis, assistente pessoal em portugues do Brasil. Chame o usuario de Chefe. Responda de forma curta, clara e acionavel. Se houver pesquisa Tavily abaixo, use-a como contexto atual. Se nao houver pesquisa, nao finja acesso em tempo real.\n\nMensagem do usuario: ' + ($json.message || '') + '\n\nPesquisa Tavily:\n' + ($json.searchContext || 'Nao foi necessario pesquisar na web para esta resposta.') + '\n\nResposta do Jarvis:').toJsonString()}},
  "stream": false,
  "options": {
    "temperature": 0.35,
    "num_predict": 300
  }
}

parameters.jsCode:
const emails = $input.all().map((item) => item.json || {});
const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};
const operation = prepared.integrationOperation || intent.operation || 'summarize_inbox';

const titles = {
  important_emails: 'emails importantes',
  career_emails: 'emails sobre carreira/estagio',
  search_emails: intent.query ? 'emails sobre ' + intent.query : 'emails encontrados',
  summarize_inbox: 'emails recentes'
};
const title = titles[operation] || 'emails recentes';

function clean(value) {
  return String(value || '')
    .replace(/[\u200B-\u200F\uFEFF]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function hasAny(text, words) {
  const lower = text.toLowerCase();
  return words.some((word) => lower.includes(word));
}

function getSender(email) {
  return clean(email.From || email.from || email.sender || email.To || email.to || 'remetente nao identificado');
}

function classify(email) {
  const subject = clean(email.Subject || email.subject || 'sem assunto');
  const from = getSender(email);
  const snippet = clean(email.snippet || email.textPlain || email.text || '');
  const haystack = [subject, from, snippet].join(' ').toLowerCase();
  const labels = [];
  let score = 0;
  let reason = '';

  if (hasAny(haystack, ['urgente', 'important', 'importante', 'deadline', 'prazo', 'vence', 'vencimento', 'acao necessaria', 'action required'])) {
    labels.push('alta prioridade');
    score += 5;
    reason ||= 'parece exigir atencao ou prazo';
  }

  if (hasAny(haystack, ['vaga', 'estagio', 'est?gio', 'entrevista', 'curriculo', 'curr?culo', 'recrutador', 'recrutamento', 'candidatura', 'processo seletivo', 'job opportunity', 'career opportunity'])) {
    labels.push('carreira/estagio');
    score += 4;
    reason ||= 'pode estar ligado a oportunidade profissional';
  }

  if (hasAny(haystack, ['boleto', 'fatura', 'pagamento', 'cobranca', 'cobran?a', 'invoice', 'recibo', 'assinatura', 'compra', 'pedido', 'pix', 'cartao', 'cart?o'])) {
    labels.push('financeiro');
    score += 3;
    reason ||= 'envolve dinheiro, compra ou assinatura';
  }

  if (hasAny(haystack, ['codigo', 'c?digo', 'verificacao', 'verifica??o', 'security', 'senha', 'login', 'acesso'])) {
    labels.push('seguranca');
    score += 3;
    reason ||= 'pode envolver acesso ou seguranca da conta';
  }

  if (hasAny(haystack, ['ollama', 'claude', 'github', 'google cloud', 'docker', 'api', 'model'])) {
    labels.push('tecnologia/aprendizado');
    score += 2;
    reason ||= 'tem relacao com tecnologia ou estudos';
  }

  if (hasAny(haystack, ['oferta', 'promo', 'desconto', 'prime video', 'paramount', 'facebook', 'newsletter', 'recomendacoes', 'recomenda??es', 'cinema'])) {
    labels.push('notificacao/promocao');
    score -= 1;
    reason ||= 'parece notificacao ou promocao';
  }

  if (!labels.length) labels.push('geral');
  if (!reason) reason = 'vale revisar quando sobrar tempo';

  let task = '';
  if (labels.includes('alta prioridade')) task = 'Revisar email urgente: ' + subject;
  else if (labels.includes('carreira/estagio')) task = 'Avaliar oportunidade de carreira: ' + subject;
  else if (labels.includes('financeiro')) task = 'Conferir item financeiro: ' + subject;
  else if (labels.includes('seguranca')) task = 'Verificar alerta de seguranca: ' + subject;

  return {
    subject,
    from,
    date: clean(email.Date || email.date || ''),
    preview: snippet.slice(0, 180),
    labels,
    score,
    reason,
    task
  };
}

if (!emails.length) {
  return [{ json: { reply: 'Chefe, nao encontrei ' + title + ' com o filtro atual.', service: 'email', operation, count: 0, suggestedTasks: [] } }];
}

const classified = emails.map(classify).sort((a, b) => b.score - a.score);
const counts = {
  alta: classified.filter((email) => email.labels.includes('alta prioridade')).length,
  carreira: classified.filter((email) => email.labels.includes('carreira/estagio')).length,
  financeiro: classified.filter((email) => email.labels.includes('financeiro')).length,
  seguranca: classified.filter((email) => email.labels.includes('seguranca')).length,
  notificacoes: classified.filter((email) => email.labels.includes('notificacao/promocao')).length
};

const top = classified.slice(0, 5);
const lines = top.map((email, index) => {
  const category = email.labels[0];
  const date = email.date ? ' - ' + email.date : '';
  const preview = email.preview ? ' Trecho: ' + email.preview : '';
  return (index + 1) + '. [' + category + '] ' + email.subject + ' - ' + email.from + date + '. Motivo: ' + email.reason + '.' + preview;
});

const suggestedTasks = classified
  .filter((email) => email.task)
  .slice(0, 5)
  .map((email) => email.task);

const nextActions = [];
if (counts.alta) nextActions.push('ver os de alta prioridade primeiro');
if (counts.carreira) nextActions.push('separar oportunidades de carreira/estagio');
if (counts.financeiro) nextActions.push('conferir pagamentos ou assinaturas');
if (!nextActions.length && counts.notificacoes) nextActions.push('arquivar notificacoes e promocoes sem urgencia');
if (!nextActions.length) nextActions.push('revisar apenas os principais quando tiver alguns minutos');

const summary = [
  'Chefe, fiz uma triagem de ' + emails.length + ' ' + title + '.',
  'Mapa rapido: alta prioridade ' + counts.alta + '; carreira/estagio ' + counts.carreira + '; financeiro ' + counts.financeiro + '; seguranca ' + counts.seguranca + '; notificacoes/promocoes ' + counts.notificacoes + '.',
  'Mais relevantes:',
  ...lines,
  suggestedTasks.length ? 'Tarefas sugeridas: ' + suggestedTasks.slice(0, 3).join('; ') + '.' : '',
  'Proxima acao sugerida: ' + nextActions.slice(0, 2).join('; ') + '.'
].filter(Boolean);

return [{
  json: {
    reply: summary.join('\n\n'),
    service: 'email',
    operation,
    count: emails.length,
    triage: counts,
    suggestedTasks
  }
}];

const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};
const text = String(prepared.message || prepared.body?.message || '').trim();

function clean(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function extractEmail(value) {
  const match = String(value || '').match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0] : '';
}

function stripCommand(value) {
  return clean(String(value || '')
    .replace(/^(jarvis[, ]*)?/i, '')
    .replace(/\b(prepare|preparar|crie|criar|faca|redija|escreva)\b/gi, '')
    .replace(/\b(um|uma)?\s*(rascunho|email|e-mail|gmail|resposta)\b/gi, '')
    .replace(/\b(para|pro|pra)\b\s*[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig, '')
  );
}

const to = intent.to || extractEmail(text);
const subjectHint = clean(intent.subject || (text.match(/(?:assunto|titulo)[: ]+([^.;]+)/i)?.[1]) || '');
const request = stripCommand(intent.query || text) || 'Agradecer o contato e informar que retornarei em breve.';
const fallbackSubject = subjectHint || 'Mensagem';
const fallbackMessage = ['Ola,', '', request, '', 'Atenciosamente,'].join('\n');

if (!to) {
  return [{ json: {
    reply: 'Chefe, consigo preparar o rascunho, mas preciso do destinatario. Diga algo como: prepare um rascunho para pessoa@email.com sobre o assunto.',
    service: 'email',
    operation: 'draft_email',
    needsRecipient: true
  } }];
}

return [{ json: {
  to,
  subjectHint,
  request,
  subject: fallbackSubject,
  message: fallbackMessage,
  service: 'email',
  operation: 'draft_email'
} }];

const draft = $input.first().json || {};
const generated = $('Formatar Rascunho IA').first().json;
const id = draft.id || draft.message?.id || draft.messageId || 'rascunho criado';
return [{ json: {
  reply: 'Chefe, rascunho inteligente criado no Gmail. Destinatario: ' + generated.to + '. Assunto: ' + generated.subject + '. Revise no Gmail. Para enviar, diga: confirmar envio. Para cancelar, diga: cancelar envio. ID: ' + id + '.',
  service: 'email',
  operation: 'draft_email',
  draftId: id,
  generatedBy: generated.generatedBy,
  pendingEmailDraft: {
    to: generated.to,
    subject: generated.subject,
    message: generated.message,
    draftId: id
  }
} }];

const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};

function clean(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

const confirmed = intent.confirmed === true || intent.confirmed === 'true';
const to = clean(intent.to);
const subject = clean(intent.subject || 'Resposta do Jarvis');
const message = String(intent.message || '').trim();

if (!confirmed) {
  return [{ json: {
    reply: 'Chefe, bloqueei o envio porque faltou confirmacao explicita.',
    service: 'email',
    operation: 'send_email_confirmed',
    blocked: true
  } }];
}

if (!to || !message) {
  return [{ json: {
    reply: 'Chefe, nao consegui enviar: faltam destinatario ou corpo do email. Prepare um rascunho de novo e confirme em seguida.',
    service: 'email',
    operation: 'send_email_confirmed',
    blocked: true
  } }];
}

return [{ json: { to, subject, message, service: 'email', operation: 'send_email_confirmed' } }];

const sent = $input.first().json || {};
const prepared = $('Preparar Envio Gmail').first().json;
const id = sent.id || sent.messageId || 'enviado';
return [{ json: {
  reply: 'Email enviado, Chefe. Destinatario: ' + prepared.to + '. Assunto: ' + prepared.subject + '. ID: ' + id + '.',
  service: 'email',
  operation: 'send_email_confirmed',
  sent: true,
  messageId: id
} }];

const item = $input.first().json || {};
return [{ json: {
  reply: item.reply || 'Chefe, envio bloqueado. Crie um rascunho e confirme explicitamente antes de enviar.',
  service: 'email',
  operation: 'send_email_confirmed',
  blocked: true
} }];

const item = $input.first().json || {};
return [{ json: {
  reply: item.reply || 'Chefe, preciso do email do destinatario para criar o rascunho.',
  service: 'email',
  operation: 'draft_email',
  needsRecipient: true
} }];

parameters.jsonBody:
={
  "model": "llama3.2:3b",
  "format": "json",
  "prompt": {{('Voce redige emails profissionais em portugues do Brasil. Retorne somente um objeto JSON valido com duas chaves: subject e message. Escreva um email natural, claro e apropriado ao pedido, sem inventar fatos, nomes, datas, compromissos ou anexos. Use no maximo 4 paragrafos curtos. Nunca use placeholders entre colchetes. Quando nao souber o nome, comece com Ola,. Quando nao souber o nome do remetente, termine apenas com Atenciosamente,. Destinatario: ' + ($json.to || '') + '\nAssunto sugerido: ' + ($json.subjectHint || 'nenhum') + '\nPedido: ' + ($json.request || '')).toJsonString()}},
  "stream": false,
  "options": {
    "temperature": 0.35,
    "num_predict": 420
  }
}

parameters.jsCode:
const prepared = $('Preparar Rascunho Gmail').first().json;
const raw = String($json.response || $json.message || '').trim();

function cleanLine(value) {
  return String(value || '').replace(/^[#*`\s]+|[#*`\s]+$/g, '').replace(/\s+/g, ' ').trim();
}

let subject = prepared.subjectHint || prepared.subject || 'Mensagem';
let message = prepared.message || '';
let generatedBy = 'fallback';

if (raw) {
  try {
    const parsed = JSON.parse(raw);
    if (parsed.subject) subject = cleanLine(parsed.subject);
    if (parsed.message) message = String(parsed.message).trim();
    generatedBy = 'ollama';
  } catch {
    const subjectMatch = raw.match(/ASSUNTO\s*:\s*([^\n\r]+)/i);
    const bodyMatch = raw.match(/CORPO\s*:\s*([\s\S]+)/i);
    if (subjectMatch?.[1]) subject = cleanLine(subjectMatch[1]);
    if (bodyMatch?.[1]) message = bodyMatch[1].trim();
    else message = raw.trim();
    generatedBy = 'ollama-fallback';
  }
}

subject = cleanLine(subject).slice(0, 180) || 'Mensagem';
message = String(message || prepared.message || '')
  .replace(/\[[^\]\n]{1,80}\]/g, '')
  .replace(/^[ \t]+$/gm, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .slice(0, 5000);

if (!message) message = prepared.message || 'Ola,\n\nObrigado pelo contato.\n\nAtenciosamente,';

return [{ json: {
  to: prepared.to,
  subject,
  message,
  request: prepared.request,
  service: 'email',
  operation: 'draft_email',
  generatedBy
} }];

const events = $input.all()
  .map((item) => item.json || {})
  .filter((event) => event.id || event.summary || event.start?.dateTime || event.start?.date);

function formatDate(value) {
  if (!value) return 'horario nao informado';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'short',
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  }).format(date);
}

const calendarEvents = events.slice(0, 30).map((event) => ({
  id: event.id || '',
  title: event.summary || 'Evento sem titulo',
  start: event.start?.dateTime || event.start?.date || '',
  end: event.end?.dateTime || event.end?.date || ''
}));

if (!events.length) {
  return [{ json: {
    reply: 'Chefe, nao encontrei compromissos no periodo consultado.',
    service: 'calendar',
    operation: 'list_calendar_events',
    count: 0,
    calendarEvents: []
  } }];
}

const lines = calendarEvents.slice(0, 10).map((event, index) =>
  (index + 1) + '. ' + event.title + ' - ' + formatDate(event.start)
);

return [{ json: {
  reply: 'Chefe, encontrei ' + events.length + ' compromisso(s):\n' + lines.join('\n'),
  service: 'calendar',
  operation: 'list_calendar_events',
  count: events.length,
  calendarEvents
} }];

const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};
const confirmed = intent.confirmed === true || intent.confirmed === 'true';
const title = String(intent.title || '').trim();
const start = String(intent.start || '').trim();
const end = String(intent.end || '').trim();
const description = String(intent.description || '').trim();
const rawReminder = intent.reminderMinutes;
const reminderMinutes = rawReminder === null || rawReminder === undefined || rawReminder === ''
  ? null
  : Math.min(40320, Math.max(0, Number(rawReminder)));

if (!confirmed || !title || !start || !end) {
  return [{ json: {
    reply: 'Chefe, bloqueei a criacao do evento porque faltou confirmacao, titulo, inicio ou fim.',
    service: 'calendar',
    operation: 'create_calendar_event_confirmed',
    blocked: true
  } }];
}

return [{ json: {
  title,
  start,
  end,
  description,
  reminderMinutes: Number.isFinite(reminderMinutes) ? reminderMinutes : null,
  service: 'calendar',
  operation: 'create_calendar_event_confirmed',
  blocked: false
} }];

const event = $input.first().json || {};
const prepared = $('Preparar Evento Agenda').first().json;
const reminder = prepared.reminderMinutes === null
  ? 'Lembretes padrao do Google Agenda.'
  : 'Lembrete por popup ' + prepared.reminderMinutes + ' minuto(s) antes.';
return [{ json: {
  reply: 'Evento criado no Google Agenda, Chefe. Titulo: ' + prepared.title + '. Inicio: ' + prepared.start + '. ' + reminder,
  service: 'calendar',
  operation: 'create_calendar_event_confirmed',
  created: true,
  eventId: event.id || '',
  reminderMinutes: prepared.reminderMinutes
} }];

const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};
const confirmed = intent.confirmed === true || intent.confirmed === 'true';
const eventId = String(intent.eventId || '').trim();
const title = String(intent.title || '').trim();
const start = String(intent.start || '').trim();
const end = String(intent.end || '').trim();
if (!confirmed || !eventId || !start || !end) {
  return [{ json: { reply: 'Chefe, bloqueei a alteracao porque faltou confirmacao ou dados do evento.', blocked: true } }];
}
return [{ json: { eventId, title, start, end, blocked: false } }];

const prepared = $('Preparar Alteracao Agenda').first().json;
return [{ json: {
  reply: 'Evento alterado no Google Agenda, Chefe. Titulo: ' + prepared.title + '. Novo inicio: ' + prepared.start + '.',
  service: 'calendar',
  operation: 'update_calendar_event_confirmed',
  updated: true
} }];

const prepared = $('Preparar Entrada').first().json;
const intent = prepared.actionIntent || prepared.body?.profile?.actionIntent || prepared.profile?.actionIntent || {};
const confirmed = intent.confirmed === true || intent.confirmed === 'true';
const eventId = String(intent.eventId || '').trim();
const title = String(intent.title || '').trim();
if (!confirmed || !eventId) {
  return [{ json: { reply: 'Chefe, bloqueei a exclusao porque faltou confirmacao ou identificacao do evento.', blocked: true } }];
}
return [{ json: { eventId, title, blocked: false } }];

const item = $input.first().json || {};
return [{ json: {
  reply: item.reply || 'Chefe, bloqueei a acao na Agenda porque faltou confirmacao explicita.',
  service: 'calendar',
  blocked: true
} }];

const prepared = $('Preparar Exclusao Agenda').first().json;
return [{ json: {
  reply: 'Evento excluido do Google Agenda, Chefe. Titulo: ' + (prepared.title || 'Compromisso') + '.',
  service: 'calendar',
  operation: 'delete_calendar_event_confirmed',
  deleted: true
} }];

const prepared = $('Preparar Entrada').first().json;
const intent = $json.actionIntent || $json.body?.profile?.actionIntent || $json.profile?.actionIntent || {};
const confirmed = intent.confirmed === true || intent.confirmed === 'true';
const to = String(intent.to || '').replace(/\D/g, '');
const message = String(intent.message || '').trim();
const validPhone = /^\d{10,15}$/.test(to);
const configured = Boolean($env.WHATSAPP_ACCESS_TOKEN && $env.WHATSAPP_PHONE_NUMBER_ID && /^v\d+\.\d+$/.test($env.WHATSAPP_GRAPH_API_VERSION || ''));
const blocked = !confirmed || !validPhone || !message || !configured;
const reply = !configured
  ? 'Chefe, a conexao oficial do WhatsApp ainda precisa do token, ID do numero e versao da API no arquivo .env.'
  : 'Chefe, bloqueei o WhatsApp porque faltou confirmacao, telefone valido ou mensagem.';
return [{ json: {
  to,
  message,
  blocked,
  service: 'whatsapp',
  operation: 'send_whatsapp_confirmed',
  reply: blocked ? reply : ''
} }];
